using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=(1<<20)+5; 
bitset<MAXN> vis;
int a[25],n,mid;
map<int,vector<int>> ml,mr;
//dfs(left)
void dfs(int num,int sum,int x)//num:now where x:status(bit->int)
{
	if(num>mid)
	{
		ml[sum].pb(x);
		return;
	}
	dfs(num+1,sum+a[num],(x|(1<<(num-1))));//OR!!!!
	dfs(num+1,sum-a[num],(x|(1<<(num-1))));
	dfs(num+1,sum,x);
}
void dfs2(int num,int sum,int x)//dfs(right)
{
	if(num>n)
	{
		mr[sum].pb(x);
		return;
	}
	dfs2(num+1,sum+a[num],(x|(1<<(num-1-mid))));
	dfs2(num+1,sum-a[num],(x|(1<<(num-1-mid))));
	dfs2(num+1,sum,x);
}
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	n=read();
	mid=n/2;
	FOR(i,1,n)
	{
		a[i]=read();
	}
	dfs(1,0,0);
	dfs2(mid+1,0,0);
    FOI(v,ml)
	{
        int p=v.fst;
        auto &lm=v.snd;
        int tp=-p;
        if(mr.find(tp)!=mr.end())
		{
            auto &rm=mr[tp];
            FOI(lk,lm)
			{
                FOI(rk,rm)
				{
                    int tot=lk|(rk<<mid);
                    vis[tot]=1;
                }
            }
        }
    }
    write(vis.count()-vis[0]);//-vis[0]!!!
    return false;
}
